    "keyLearningPoints": [
      "Status epilepticus = seizure >5 minutes or recurrent seizures without return to baseline — this is a medical emergency",
      "Treatment ladder: (1) Benzodiazepine → (2) IV fosphenytoin or levetiracetam or valproate → (3) Intubation + propofol/midazolam drip",
      "Medication non-compliance is the #1 cause of status epilepticus in known epileptics",
      "Check glucose IMMEDIATELY — hypoglycemia is the most treatable mimic",
      "Rhabdomyolysis is a major complication — aggressive IV fluids, monitor CK and creatinine",
      "Fever in status epilepticus is from prolonged muscle activity, not necessarily infection — but still consider meningitis/encephalitis"
    ],
    "mustNotMiss": [
      "Hypoglycemia (check point-of-care glucose before anything else)",
      "Meningitis/encephalitis (if any suspicion: LP after CT, empiric antibiotics)",
      "Intracranial hemorrhage (CT head urgently)",
      "Eclampsia (pregnancy test in women of childbearing age)",
      "Hyponatremia (<120 can cause seizures)"
    ],
    "commonPitfalls": [
      "Underdosing benzodiazepines — lorazepam 0.1mg/kg IV, can repeat",
      "Waiting too long to escalate to second-line agent (if seizing after 2 doses of benzo, move on)",
      "Not intubating when respiratory drive is compromised by medications or prolonged postictal state",
      "Attributing fever to seizure without ruling out CNS infection",
      "Missing alcohol withdrawal as co-precipitant alongside medication non-compliance",
      "Not checking CK — rhabdomyolysis can cause renal failure if untreated"
    ],
