          "name": "Airway monitoring+ENT standby",
          "group": "Airway",
          "critical": true,
          "correct": true,
          "phase": 1,
          "teaching": "Laryngeal AE causes 30% HAE deaths. LOW intubation threshold. Fiberoptic preferred.",
