  "sjs-ten-v2": {
    "id": "sjs-ten-v2",
    "diagnosis": "SJS/TEN (Lamotrigine)",
    "acuity": 1,
    "presentation": "Drug Reaction",
    "category": "allergy",
    "chiefComplaint": "Skin Detachment/Mucosal Erosions",
    "treatments": {
      "orders": [
        {
          "id": "stop-sjs-ten-",
          "name": "Stop lamotrigine",
          "group": "First-line",
          "critical": true,
          "correct": true,
          "phase": 1,
          "teaching": "The venom immunotherapy injection must be stopped immediately at the first sign of any systemic reaction — no additional venom should be administered. The patient should remain in the allergy clinic for a minimum of 30 minutes observation after every VIT injection, as most systemic reactions occur within this window. Premature departure after injections significantly increases fatal outcome risk.",
          "references": [
            {
              "source": "SJS TEN",
              "url": "https://www.ncbi.nlm.nih.gov/books/NBK459323/",
              "detail": "Stop drug"
            }
          ]
        },
        {
          "id": "burn",
          "name": "Burn unit/ICU",
          "group": "Critical",
          "critical": true,
          "correct": true,
          "phase": 1,
          "teaching": "HIV-positive patients with SJS/TEN have significantly higher mortality than HIV-negative patients — immune dysregulation impairs keratinocyte recovery, opportunistic infections complicate the wound, and TMP-SMX (the most common causative drug in HIV patients, used for PCP prophylaxis) must be permanently discontinued. Alternative PCP prophylaxis (dapsone — check G6PD first, atovaquone, or inhaled pentamidine) must be arranged before discharge.",
          "references": [
            {
              "source": "SJS TEN",
              "url": "https://www.ncbi.nlm.nih.gov/books/NBK459323/",
              "detail": "Burn unit"
            }
          ]
        },
        {
          "id": "ivf-sjs-ten-",
          "name": "Aggressive IVF",
          "group": "Resuscitation",
          "critical": true,
          "correct": true,
          "phase": 1,
          "teaching": "IV fluid resuscitation with 1–2L isotonic crystalloid (normal saline or LR) rapidly corrects the distributive hypotension of anaphylaxis by replacing the intravascular volume lost to massive vasodilation and capillary leak. Use cautiously in elderly patients and those with known cardiac disease — aggressive fluid resuscitation can precipitate pulmonary edema in patients with impaired LV function.",
          "references": [
            {
              "source": "SJS TEN",
              "url": "https://www.ncbi.nlm.nih.gov/books/NBK459323/",
              "detail": "IVF"
            }
          ]
        },
        {
          "id": "eye",
          "name": "Ophthalmology STAT",
          "group": "Consult",
          "critical": true,
          "correct": true,
          "phase": 1,
          "teaching": "Ocular complications of SJS/TEN in HIV patients are particularly severe — conjunctival pseudomembrane formation and fornix adhesions can progress to permanent conjunctival scarring, corneal pannus formation, and blindness if not aggressively managed. Daily ophthalmology assessment with amniotic membrane transplantation (AMT) in the acute phase is the standard of care at experienced centers. Preservative-free lubricating drops, topical antibiotic prophylaxis, and lysis of forming symblepharon rings are performed daily.",
          "references": [
            {
              "source": "SJS TEN",
              "url": "https://www.ncbi.nlm.nih.gov/books/NBK459323/",
              "detail": "Ophthalmology"
            }
          ]
        },
        {
          "id": "scorten",
          "name": "SCORTEN score",
          "group": "Prognostic",
          "critical": false,
          "correct": true,
          "phase": 1,
          "teaching": "SCORTEN (SCORe of Toxic Epidermal Necrosis) predicts SJS/TEN mortality using 7 variables scored within 24 hours: age >40, malignancy, tachycardia >120, initial BSA detachment >10%, serum urea >10 mmol/L, glucose >14 mmol/L, bicarbonate <20 mmol/L. Score 0–1: 3% mortality; score ≥5: >90% mortality. SCORTEN guides ICU admission decisions, family counseling, and goals-of-care discussions.",
          "references": [
            {
              "source": "SJS TEN",
              "url": "https://www.ncbi.nlm.nih.gov/books/NBK459323/",
              "detail": "SCORTEN"
            }
          ]
        },
        {
          "id": "sulfa",
          "name": "TMP-SMX for infection",
          "group": "Abx",
          "critical": false,
          "correct": false,
          "phase": 1,
          "teaching": "Sulfonamide antibiotics (trimethoprim-sulfamethoxazole being most common) are the leading drug cause of SJS/TEN, followed by allopurinol, aromatic anticonvulsants (phenytoin, carbamazepine, lamotrigine), and NSAIDs (particularly oxicam class). TMP-SMX must be documented as permanently contraindicated — all sulfonamide-containing medications are cross-reactive and must be avoided. Alternative PCP prophylaxis (dapsone, atovaquone, inhaled pentamidine) is required.",
          "references": [
            {
              "source": "SJS TEN",
              "url": "https://www.ncbi.nlm.nih.gov/books/NBK459323/",
              "detail": "Sulfa dangerous"
            }
          ]
        },
        {
          "id": "continue-lamotrigine-v2",
          "name": "Continue lamotrigine at lower dose — seizure control is critical",
          "correct": false,
          "phase": 1,
          "teaching": "Lamotrigine must be stopped immediately and permanently in SJS/TEN — there is no safe lower dose. Continued exposure drives ongoing keratinocyte apoptosis and worsens skin detachment. Alternative anticonvulsants (levetiracetam, valproate, topiramate) that do not cause SJS/TEN must be started urgently in consultation with neurology. Seizure control is important, but it cannot be prioritized over stopping the drug that is causing potentially fatal skin necrosis.",
          "references": [
            {
              "source": "SJS/TEN — StatPearls",
              "url": "https://www.ncbi.nlm.nih.gov/books/NBK459323/",
              "detail": "Causative drug stopped immediately and permanently; no safe dose reduction"
            },
            {
              "source": "SJS/TEN Drug Management — PMC",
              "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC7552546/",
              "detail": "Alternative anticonvulsants required urgently; dose reduction is not an option"
            }
          ]
        }
      ],
      "phases": [
        {
          "id": "initial",
          "label": "Presentation",
          "auto": true,
          "vitals": {
            "BP": "98/62",
            "HR": "118",
            "RR": "22",
            "Temp": "102.8F",
            "SpO2": "95%"
          },
          "ecg": "Sinus tachycardia",
          "labHighlights": {},
          "examNote": "28yo. Lamotrigine 2wk (titrated too fast). Targetoid lesions, Nikolsky+. Oral/genital erosions. BSA 25%."
        },
        {
          "id": "treated",
          "label": "Managed",
          "requires": [
            "stop",
            "burn",
            "eye"
          ],
          "vitals": {
            "BP": "108/68",
            "HR": "102",
            "RR": "20",
            "Temp": "101.2F",
            "SpO2": "96%"
          },
          "ecg": "NSR",
          "labHighlights": {},
          "examNote": "Burn unit. Amniotic membrane grafts for eyes. SCORTEN 2.",
          "aiPatientUpdate": null,
          "teaching": "Lamotrigine SJS from rapid titration. Ophthalmology MANDATORY. SCORTEN predicts mortality."
        }
      ],
      "pitfallEvents": [
        {
          "trigger": "sulfa",
          "event": "worsening",
          "message": "Sulfa worsened reaction dramatically.",
          "recovery": "Stop sulfa. Escalate care.",
          "vitals": {}
        }
      ]
    },
    "keyLearningPoints": [
      "Lamotrigine: slow titration prevents SJS",
      "Ophthalmology mandatory",
      "SCORTEN",
      "Nikolsky sign",
      "BSA classification"
    ],
    "mustNotMiss": [
      "Airway from mucosal involvement",
      "Sepsis from skin loss",
      "Blindness"
    ],
    "commonPitfalls": [
      "Rapid titration",
      "Sulfa in SJS patient",
      "No ophthalmology",
      "Aggressive debridement"
    ]
  },
